def advanced_search(request):
    request_json = request.get_json(silent=True)
    request_args = request.args
    
    db_user = os.environ.get('DB_USER', 'root')
    db_password = os.environ.get('DB_PASSWORD', '')
    db_name = os.environ.get('DB_NAME', 'mydatabase')
    db_host = os.environ.get('DB_HOST', 'localhost')
    
    connection = pymysql.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name,
        cursorclass=pymysql.cursors.DictCursor
    )
    
    try:
        with connection.cursor() as cursor:
            base_table = request_args.get('table', 'users')
            columns = request_args.get('columns', '*')
            
            query = f"SELECT {columns} FROM {base_table}"
            
            if 'join_table' in request_args:
                join_table = request_args.get('join_table')
                join_on = request_args.get('join_on', 'id')
                join_type = request_args.get('join_type', 'INNER')
                query += f" {join_type} JOIN {join_table} ON {base_table}.{join_on} = {join_table}.{join_on}"
            
            where_clauses = []
            
            for key in request_args.keys():
                if key.startswith('filter_'):
                    field = key.replace('filter_', '')
                    value = request_args.get(key)
                    operator = request_args.get(f'op_{field}', '=')
                    
                    if operator in ['=', '>', '<', '>=', '<=', '!=', 'LIKE']:
                        if operator == 'LIKE':
                            where_clauses.append(f"{field} LIKE '%{value}%'")
                        elif operator in ['=', '!='] and not value.isdigit():
                            where_clauses.append(f"{field} {operator} '{value}'")
                        else:
                            where_clauses.append(f"{field} {operator} {value}")
            
            if 'where' in request_args:
                custom_where = request_args.get('where')
                where_clauses.append(f"({custom_where})")
            
            if where_clauses:
                query += " WHERE " + " AND ".join(where_clauses)
            
            if 'group_by' in request_args:
                group_by = request_args.get('group_by')
                query += f" GROUP BY {group_by}"
            
            if 'having' in request_args:
                having = request_args.get('having')
                query += f" HAVING {having}"
            
            if 'order_by' in request_args:
                order_by = request_args.get('order_by')
                order_dir = request_args.get('order_dir', 'ASC')
                query += f" ORDER BY {order_by} {order_dir}"
            
            if 'limit' in request_args:
                limit = request_args.get('limit')
                query += f" LIMIT {limit}"
                
                if 'offset' in request_args:
                    offset = request_args.get('offset')
                    query += f" OFFSET {offset}"
            
            cursor.execute(query)
            results = cursor.fetchall()
            
            return jsonify({
                'success': True,
                'count': len(results),
                'data': results
            })
    
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500
    
    finally:
        connection.close()